Here's a complete implementation for an MCP server wrapping a REST API with stdio transport.

## Tool Class — `ApiTools.cs`

```csharp
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a user by their unique ID.")]
    public async Task<string> GetUser(
        [Description("The user's numeric ID")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search users by name. Returns matching results as JSON.")]
    public async Task<string> SearchUsers(
        [Description("Name or partial name to search for")] string query,
        [Description("Max results to return (1-50)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users: {Query}, limit={Limit}", query, limit);
        var response = await httpClient.GetAsync(
            $"/users?q={Uri.EscapeDataString(query)}&limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Get a summary of total users and recent signups.")]
    public async Task<string> GetUserStats(
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync("/users/stats", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}
```

## `Program.cs` — stdio transport

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: log to stderr only — stdout is the JSON-RPC protocol channel
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient<ApiTools>(client =>
{
    client.BaseAddress = new Uri("https://api.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();
```

## How DI Works for MCP Tools

The SDK supports **two injection styles**:

### 1. Constructor injection (non-static class) — shown above
The class is instantiated per-request. Services like `HttpClient` and `ILogger<T>` are resolved from the DI container and passed via the primary constructor. These **never** appear in the tool's JSON schema.

### 2. Method parameter injection (static class)
DI services can also be method parameters on static tool methods:

```csharp
[McpServerToolType]
public static class StaticApiTools
{
    [McpServerTool, Description("Ping the API.")]
    public static async Task<string> Ping(
        HttpClient httpClient,              // ← injected by DI, hidden from schema
        [Description("Endpoint path")] string path,  // ← exposed to LLM
        CancellationToken cancellationToken = default)
    {
        var r = await httpClient.GetAsync(path, cancellationToken);
        return $"Status: {r.StatusCode}";
    }
}
```

**Key rules:**
- Parameters with `[Description]` → exposed in the tool schema (LLM sees them)
- `CancellationToken`, `IMcpServer`, `IProgress<T>`, and any DI-registered service → injected automatically, hidden from schema
- `.WithToolsFromAssembly()` discovers all `[McpServerToolType]` classes via reflection
- For Native AOT, use `.WithTools<ApiTools>()` instead
